SELECT t, datacenter, sum(tx_bytesIncrease) AS tx_bytesIncreaseAgg, sum(rx_bytesIncrease) AS rx_bytesIncreaseAgg FROM (  SELECT t, datacenter, dc_interface, if(runningDifference(tx_bytes) < 0 OR neighbor(dc_interface,-1,dc_interface) != dc_interface, nan, runningDifference(tx_bytes) / 1) AS tx_bytesIncrease, if(runningDifference(rx_bytes) < 0 OR neighbor(dc_interface,-1,dc_interface) != dc_interface, nan, runningDifference(rx_bytes) / 1) AS rx_bytesIncrease  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, datacenter, concat(datacenter, interface) AS dc_interface, max(tx_bytes) AS tx_bytes, max(rx_bytes) AS rx_bytes   FROM traffic WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY datacenter, dc_interface, t    ORDER BY datacenter, dc_interface, t  ) ) GROUP BY datacenter, t ORDER BY datacenter, t